mapper.select:
SELECT 
  FROM er.tn_er_acft_fuel f
 WHERE f.er_id   = #{erId}
   AND f.acft_sn = #{acftSn}
   AND NOW() BETWEEN f.use_bgng_dt AND f.use_end_dt

SELECT COALESCE(MAX(acft_sn), 0) + 1
  FROM er.tn_er_acft_fuel
 WHERE er_id = #{erId}

SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
  FROM er.tn_er_acft_fuel
 WHERE er_id      = #{erId}
   AND regis_mark = #{regisMark}
   AND acft_sn   != #{excludeSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.update:
UPDATE er.tn_er_acft_fuel
   SET use_end_dt        = NOW() - INTERVAL '1 minute',
       last_chg_dt       = NOW(),
       last_chg_user_id  = #{userId}
 WHERE er_id   = #{erId}
   AND acft_sn = #{acftSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
